#              collector: writes the collector script and its LaunchDaemon,
#              then loads the daemon. --uninstall removes everything.
# Context:     Jamf policy (as root) or standalone: sudo ./install.sh [--uninstall]
# Parameters:  $4 = action: blank/install or --uninstall/uninstall
#              $5 = reverse-DNS label prefix, default io.github.ai-software-inventory
#              $6 = collection interval seconds, default 14400, minimum 600
#              $7 = absolute log path, default /var/log/ai-software-inventory.collector.log
# Tested on:   macOS 15.7.7 Sequoia
# Author:      Robert Flanagan (@r4828)
#
# $6 is recorded in ${STATE_DIR}/interval; the EA reader derives its staleness
# threshold (2x interval) from that file, falling back to 28800 s if absent.

set -eu
umask 022

REVERSE_DOMAIN="${5:-io.github.ai-software-inventory}"
# The label lands in a filesystem path and in plist XML; keep it reverse-DNS.
case "${REVERSE_DOMAIN}" in
    *[!A-Za-z0-9.-]*|*..*|.*|*.)
        echo "install.sh: parameter 5 (REVERSE_DOMAIN) must be a reverse-DNS label (letters, digits, '.', '-'), got '${REVERSE_DOMAIN}'" >&2
        exit 1
        ;;
esac
PROJECT="ai-software-inventory"
START_INTERVAL="${6:-14400}"

LABEL="${REVERSE_DOMAIN}.collector"
INSTALL_DIR="/usr/local/${PROJECT}"
COLLECTOR_NAME="ai-inventory-collector.zsh"
COLLECTOR_DEST="${INSTALL_DIR}/${COLLECTOR_NAME}"
PLIST_DEST="/Library/LaunchDaemons/${LABEL}.plist"
STATE_DIR="/var/db/${PROJECT}"
LOG_FILE="${7:-/var/log/${PROJECT}.collector.log}"

# Fail visibly on a bad cadence.
case "${START_INTERVAL}" in
    ''|*[!0-9]*)
        echo "install.sh: parameter 6 (START_INTERVAL) must be an integer number of seconds, got '${START_INTERVAL}'" >&2
        exit 1
        ;;
esac
if [ "${START_INTERVAL}" -lt 600 ]; then
    echo "install.sh: parameter 6 (START_INTERVAL) must be >= 600 seconds, got ${START_INTERVAL}" >&2
    exit 1
fi

# LaunchDaemon log paths must be absolute.
case "${LOG_FILE}" in
    /*) : ;;
    *)
        echo "install.sh: parameter 7 (LOG_FILE) must be an absolute path, got '${LOG_FILE}'" >&2
        exit 1
        ;;
esac

log() {
    echo "[install.sh] $*"
}

do_uninstall() {
    log "Uninstalling ${LABEL} ..."
    if [ ! -f "${PLIST_DEST}" ]; then
        log "WARNING: ${PLIST_DEST} not found. If the install used a custom parameter 5 (label prefix), rerun --uninstall with that same value; continuing cleanup of the paths above."
    fi
    launchctl bootout "system/${LABEL}" 2>/dev/null || true
