#!/bin/zsh --no-rcs
# SPDX-FileCopyrightText: 2026 Robert Flanagan and macadmin-toolbox contributors
# SPDX-License-Identifier: MIT
#
# Name:        ai-inventory-collector.zsh
# Purpose:     Background collector for the Jamf AI Software Inventory EA.
#              Scans local apps/tools/configs and writes the EA inner value
#              to /var/db/ai-software-inventory/result.txt. Do not wrap output
#              in <result>; ai-software-inventory-ea.zsh does that during recon.
# Context:     LaunchDaemon (installed by install.sh); runs as root on a timer.
# Parameters:  none
# Tested on:   macOS 15.7.7 Sequoia
# Author:      Robert Flanagan (@r4828)
#
# No network calls. Team-ID matches are verified with offline codesign.

export PATH="/usr/bin:/bin:/usr/sbin:/sbin"

# Use fixed paths; launchd's PATH is not an API.
GREP=/usr/bin/grep
SED=/usr/bin/sed
AWK=/usr/bin/awk
FIND=/usr/bin/find
SORT=/usr/bin/sort
TR=/usr/bin/tr
HEAD=/usr/bin/head
MKTEMP=/usr/bin/mktemp
BASENAME=/usr/bin/basename
DIRNAME=/usr/bin/dirname
CUT=/usr/bin/cut
PLUTIL=/usr/bin/plutil
CODESIGN=/usr/bin/codesign
MKDIR=/bin/mkdir
MV=/bin/mv
CHOWN=/usr/sbin/chown
CHMOD=/bin/chmod

# Do not use err_exit: most scan paths are optional and expected to miss.

umask 077   # any temp we create is root-only until explicitly chmod'd below

# Must match ai-software-inventory-ea.zsh.
: ${AI_INV_STATE_DIR:=/var/db/ai-software-inventory}
STATE_DIR="$AI_INV_STATE_DIR"
STATE_FILE="$STATE_DIR/result.txt"

# Accumulate TAB-separated findings: CATEGORY, Friendly, id, location.
# Fallback temp path is root-only, never world-writable /tmp.
WORK="$("$MKTEMP" -t ai_sw_inv.XXXXXX 2>/dev/null)" || WORK="/var/root/.ai_sw_inv.$$"
WORK_OK=1
: > "$WORK" 2>/dev/null || WORK_OK=0
trap 'rm -f "$WORK" "$STATE_FILE.tmp.$$" 2>/dev/null' EXIT   # also reaps an orphaned state tmpfile if killed mid-rename

# Escape user-controlled names before the EA reader wraps them in <result>.
xesc() {
    local s=$1
    s=${s//[[:cntrl:]]/ }
    s=${s//&/&amp;}
    s=${s//</&lt;}
    s=${s//>/&gt;}
    print -r -- "$s"
}

emit() { # emit CATEGORY  Friendly  id  location
    printf '%s\t%s\t%s\t%s\n' "$1" "$(xesc "$2")" "$(xesc "$3")" "$(xesc "$4")" >> "$WORK"
}

# Real user homes only; (N/) means directories, null if none.
user_homes=()
for h in /Users/*(N/); do
    case "$h" in
        /Users/Shared|/Users/.localized|/Users/Guest) continue ;;
    esac
    user_homes+=("$h")
done

lc() { printf '%s' "$1" | "$TR" '[:upper:]' '[:lower:]'; }

# Conservative AI-token heuristic; avoid bare ai/gpt/amp/zed false positives.
AI_HEURISTIC='chatgpt|openai|anthropic|claude|copilot|codeium|windsurf|cursor|gemini|ollama|llama|mistral|perplexity|tabnine|gpt4all|lm.?studio|deepseek|hugging.?face|langchain|comfyui|diffusionbee|stable.?diffusion|whisper|open.?interpreter|localai|jan\.ai|msty|anythingllm|generative.?ai|\bllm\b|genai|\bgpt-?[0-9]|openhands|gptme|ra-?aid|gpt-?engineer|mentat|codebuff|plandex|codegeex|auggie|qodo'

is_ai_heuristic() { printf '%s' "$1" | "$GREP" -Eiq "$AI_HEURISTIC"; }

# Curated AI-native Developer ID teams only. Diversified vendors are handled by
# bundle ID/name because they sign non-AI apps too.
teamid_known() {
    case "$1" in
        Q6L2SF6YDW) echo "Anthropic";;
        2DC432GLL2) echo "OpenAI";;
        D65G88RHWN) echo "Element Labs (LM Studio)";;
        3MU9H2V9Y9) echo "Infra Technologies (Ollama)";;
        7S8W4W365S) echo "Perplexity";;
        83GA966S9H) echo "PLAUD";;
        YJ5GSB3AMW) echo "Chatbox";;
        GJE9R5VE87) echo "ChatWise";;
        TPKP4XK352) echo "Pinokio";;
        6HP3U6Z7P6) echo "Draw Things";;
        QZ7DHHLN25) echo "Granola";;
        6AWUP5FE76) echo "Otter.ai";;
        U5R26XM5Z2) echo "Krisp";;
        DM5Z66639F) echo "Fireflies.ai";;
        89PS65RKC6) echo "Cluely";;
        6D5N473QP3) echo "BoltAI";;
        TP8BYQ64C4) echo "Witsy";;
        T7FPYN38JJ) echo "Tabnine";;
        83Z2LHX6XW) echo "Exafunction (Windsurf/Codeium/Devin)";;
        *) echo "";;
    esac
}

app_teamid() { # print the app's code-signing Team Identifier, or empty
    "$CODESIGN" -dv --verbose=4 "$1" 2>&1 | "$AWK" -F= '/^TeamIdentifier=/{print $2; exit}'
}

# Offline signature check for Team-ID matches. Do not replace this with spctl.
verify_signature() { "$CODESIGN" --verify "$1" >/dev/null 2>&1; }

