scan_apps() {
    local -a roots
    local h app base bid blob friendly team vendor
    roots=(/Applications /Applications/Utilities /System/Applications/Utilities)
    for h in $user_homes; do roots+=("$h/Applications"); done
    # Covers /Applications/Vendor/Thing.app without deep recursion.
    "$FIND" $roots -maxdepth 3 -name '*.app' -type d -prune 2>/dev/null | while IFS= read -r app; do
        base="$("$BASENAME" "$app" .app)"
        bid="$("$PLUTIL" -extract CFBundleIdentifier raw -o - "$app/Contents/Info.plist" 2>/dev/null)"
        blob="$(lc "$base $bid")"

        friendly="$(app_known "$blob")"
        if [[ -n "$friendly" ]]; then
            emit "APP" "$friendly" "${bid:-$base}" "$app"
            continue
        fi

        # Team-ID fallback only runs after name/bundle matching.
        team="$(app_teamid "$app")"
        vendor="$(teamid_known "$team")"
        if [[ -n "$vendor" ]]; then
            if verify_signature "$app"; then
                emit "APP" "$base (Developer ID: $vendor)" "${bid:-$base} [Team $team verified]" "$app"
            else
                # Keep failed Team-ID matches visible for review.
                emit "HEURISTIC" "$base (Developer ID: $vendor, signature FAILED verify)" "${bid:-$base} [Team $team UNVERIFIED]" "$app"
            fi
        elif [[ -n "$bid" ]] && printf '%s' "$bid" | "$GREP" -Eiq '^ai\.'; then
            emit "HEURISTIC" "$base (reverse-domain .ai vendor)" "$bid" "$app"
        elif is_ai_heuristic "$blob"; then
            emit "HEURISTIC" "$base (AI keyword)" "${bid:-$base}" "$app"
        fi
    done
}

# SECTION B: AI command-line tools and coding agents.
# Generic binary names are detected by config/package evidence, not bare name.
cli_known() {
    case "$1" in
        claude)                 echo "Claude Code (Anthropic)";;
        codex)                  echo "OpenAI Codex";;
        gemini)                 echo "Gemini CLI (Google)";;
        cursor-agent)           echo "Cursor Agent";;
        aider)                  echo "Aider";;
        ollama)                 echo "Ollama (local LLM runtime)";;
        llm)                    echo "llm CLI (Datasette)";;
        sgpt|shell-gpt)         echo "Shell GPT";;
        mods)                   echo "mods (Charm)";;
        aichat)                 echo "aichat";;
        tgpt)                   echo "tgpt";;
        crush)                  echo "Crush (Charm)";;
        opencode)               echo "OpenCode";;
        kiro|kiro-cli)          echo "Kiro CLI";;
        cody)                   echo "Sourcegraph Cody";;
        chatgpt)                echo "ChatGPT CLI";;
        interpreter|open-interpreter) echo "Open Interpreter";;
        llamafile|llama-cli|llama-server) echo "llama.cpp";;
        amp)                    echo "Amp (Sourcegraph)";;
        openhands)              echo "OpenHands";;
        cline)                  echo "Cline";;
        auggie)                 echo "Auggie (Augment)";;
        qodo)                   echo "Qodo Command";;
        codebuff|freebuff)      echo "Codebuff";;
        ra-aid)                 echo "RA.Aid";;
        fabric)                 echo "Fabric";;   # not in the PATH-scan list; Fabric is detected via ~/.config/fabric below
        gptme)                  echo "gptme";;
        gpte|gpt-engineer)      echo "gpt-engineer";;
        plandex|pdx)            echo "Plandex";;
        butterfish)             echo "Butterfish";;
        mycoder)                echo "MyCoder";;
