        qchat|qterm)            echo "Amazon Q";;
        *) echo "";;
    esac
}

scan_cli() {
    # Binaries in system and per-user bin locations.
    local -a bindirs simple_cli_configs npmroots aiderhits
    local h d name entry suffix friendly r pkg pdir v vn
    bindirs=(/usr/local/bin /opt/homebrew/bin /opt/local/bin /usr/bin)
    for h in $user_homes; do
        bindirs+=("$h/.local/bin" "$h/bin" "$h/.npm-global/bin" "$h/.cargo/bin" "$h/.deno/bin" "$h/.bun/bin" \
                  "$h/Library/pnpm" "$h/.volta/bin" "$h/.asdf/shims" "$h/.claude/local")
    done
    for d in $bindirs; do
        [[ -d "$d" ]] || continue
        # No bare "copilot" or "goose" here: AWS Copilot (ECS) and pressly/goose
        # (database migrations) install binaries with those exact names. GitHub
        # Copilot CLI is caught by ~/.config/github-copilot and the
        # @github/copilot npm package; Block's Goose by ~/.config/goose.
        for name in claude codex gemini cursor-agent aider ollama llm sgpt shell-gpt \
                    mods aichat tgpt crush opencode kiro kiro-cli cody \
                    chatgpt interpreter open-interpreter llamafile llama-cli llama-server \
                    amp openhands cline auggie qodo codebuff freebuff ra-aid gptme \
                    gpte gpt-engineer plandex pdx butterfish mycoder mentat qchat qterm; do
            if [[ -e "$d/$name" || -L "$d/$name" ]]; then
                friendly="$(cli_known "$name")"
                [[ -n "$friendly" ]] && emit "CLI" "$friendly" "$name" "$d/$name"
            fi
        done
    done

    # Config/state dirs catch shims and tools with generic binary names.
    simple_cli_configs=(
        ".codex|OpenAI Codex (config present)"
        ".gemini|Gemini CLI (config present)"
        ".config/github-copilot|GitHub Copilot CLI (config present)"
        ".ollama|Ollama (config present)"
        ".continue|Continue CLI (config present)"
        ".openhands|OpenHands (config present)"
        ".augment|Auggie/Augment (config present)"
        ".qodo|Qodo (config present)"
        ".cline|Cline (config present)"
        ".forge|ForgeCode (config present)"
        ".factory|Factory Droid (config present)"
        ".grok|Grok CLI (config present)"
        ".mycoder|MyCoder (config present)"
        ".config/amp|Amp (config present)"
        ".config/goose|Goose (Block) (config present)"
        ".config/fabric|Fabric (config present)"
    )
    for h in $user_homes; do
        { [[ -e "$h/.claude" || -e "$h/.claude.json" ]]; } && emit "CLI" "Claude Code (config present)" "~/.claude" "$h/.claude"
        aiderhits=($h/.aider*(N))
        { [[ -d "$h/.aider" ]] || (( ${#aiderhits} )); } && emit "CLI" "Aider (config present)" "~/.aider" "$h/.aider*"
        { [[ -d "$h/.aws/amazonq" || -d "$h/.aws/q" ]]; } && emit "CLI" "Amazon Q Developer CLI (config present)" "~/.aws/amazonq" "$h/.aws/amazonq"
        for entry in $simple_cli_configs; do
            suffix="${entry%%|*}"
            friendly="${entry#*|}"
            [[ -d "$h/$suffix" ]] && emit "CLI" "$friendly" "~/$suffix" "$h/$suffix"
        done
    done

    # npm globals across system and per-user prefixes.
    npmroots=(/opt/homebrew/lib/node_modules /usr/local/lib/node_modules)
    for h in $user_homes; do
        npmroots+=(
            $h/.npm-global/lib/node_modules(N)
            $h/.nvm/versions/node/*/lib/node_modules(N)
            $h/n/lib/node_modules(N)
            $h/.config/yarn/global/node_modules(N)
        )
    done
    for r in $npmroots; do
        [[ -d "$r" ]] || continue
        for pkg in "@anthropic-ai/claude-code" "@openai/codex" "@google/gemini-cli" \
                   "@github/copilot" "opencode-ai" "@sourcegraph/cody" "@sourcegraph/amp" \
                   "@qwen-code/qwen-code" "@continuedev/cli" "@augmentcode/auggie" \
                   "@qodo/command" "codebuff" "@antinomyhq/forge" "cline" "mycoder" \
                   "@vibe-kit/grok-cli" "@shareai-lab/kode"; do
            [[ -d "$r/$pkg" ]] && emit "CLI" "npm: $pkg" "$pkg" "$r/$pkg"
        done
    done

    # pipx-managed AI CLIs.
    for h in $user_homes; do
        for pdir in "$h/.local/pipx/venvs" "$h/.local/share/pipx/venvs"; do
            [[ -d "$pdir" ]] || continue
            for v in $pdir/*(N); do
                [[ -d "$v" ]] || continue
                vn="$("$BASENAME" "$v")"
                is_ai_heuristic "$vn" && emit "CLI" "pipx: $vn" "$vn" "$v"
            done
        done
        # uv-managed tools.
        for v in "$h/.local/share/uv/tools"/*(N); do
            [[ -d "$v" ]] || continue
            vn="$("$BASENAME" "$v")"
            is_ai_heuristic "$vn" && emit "CLI" "uv: $vn" "$vn" "$v"
        done
    done
}

# SECTION C: Editor AI extensions/plugins.
ext_is_ai() {
    local lc_name
    lc_name="$(lc "$1")"
    case "$lc_name" in
        github.copilot*|continue.continue*|codeium.*|tabnine.*|sourcegraph.cody*|\
        sourcegraph.amp*|saoudrizwan.claude-dev*|rooveterinaryinc.roo-cline*|kilocode.*|\
        supermaven.*|google.geminicodeassist*|\
        amazonwebservices.amazon-q*|anthropic.*|\
        openai.*|blackboxapp.*|codegpt.*|danielsanmedium.dscodegpt*|\
        visualstudioexptteam.vscodeintellicode*|mintlify.*|bito.*|\
        sourcery.sourcery*|codium.codium*|augment.*|pythagora-io.*|\
        aminer.codegeex*|rjmacarthy.twinny*|tabbyml.*|doublebot.doublebot*|\
        codestoryai.*|meshintelligenttechnologiesinc.pieces*|alibaba-cloud.tongyi-lingma*|\
        marscode.*|baiducomate.*|smallcloud.codify*|zencoderai.*|sweepai.*|bloop.*|\
        codiga.*|mistralai.mistral-code*|ms-windows-ai-studio.*|venthe.fauxpilot*|\
        sitoi.ai-commit*|codemateai.*|askcodi.*)
            return 0;;
    esac
    is_ai_heuristic "$lc_name" && return 0
    return 1
}

scan_ide_ext() {
    local h extroot editor e en pubname jb p
    for h in $user_homes; do
        for extroot in "$h/.vscode/extensions" "$h/.vscode-insiders/extensions" \
                       "$h/.vscode-oss/extensions" "$h/.vscodium/extensions" \
                       "$h/.cursor/extensions" "$h/.windsurf/extensions" \
                       "$h/.antigravity/extensions"; do
            [[ -d "$extroot" ]] || continue
            editor="$("$BASENAME" "$("$DIRNAME" "$extroot")")"   # e.g. ".cursor"
            for e in $extroot/*(N); do
                [[ -d "$e" ]] || continue
                en="$("$BASENAME" "$e")"                       # publisher.name-version
                pubname="$(printf '%s' "$en" | "$SED" -E 's/-[0-9]+\.[0-9]+\.[0-9]+.*$//')"
                if ext_is_ai "$pubname"; then
                    emit "IDE-EXT" "$pubname" "$editor" "$e"
                fi
            done
        done
        # JetBrains plugin folders.
        jb="$h/Library/Application Support/JetBrains"
        [[ -d "$jb" ]] || continue
        "$FIND" "$jb" -maxdepth 3 -type d \( -iname '*copilot*' -o -iname '*codeium*' \
             -o -iname '*cody*' -o -iname '*ai-assistant*' -o -iname '*tabnine*' \
             -o -iname '*codegeex*' -o -iname '*codegpt*' -o -iname '*continue*' \
             -o -iname '*refact*' -o -iname '*amazon*q*' -o -iname '*marscode*' \
             -o -iname '*lingma*' -o -iname '*comate*' -o -iname '*zencoder*' \
             -o -iname '*supermaven*' -o -iname '*bito*' \) 2>/dev/null | while IFS= read -r p; do
            emit "IDE-EXT" "$("$BASENAME" "$p")" "JetBrains" "$p"
        done
    done
}

