# Bounded manifest-name scan for unknown extensions.
scan_browser_ext() {
    local h broot browser mf extid known nm extdir msg
    for h in $user_homes; do
        for broot in \
            "$h/Library/Application Support/Google/Chrome" \
            "$h/Library/Application Support/Google/Chrome Beta" \
            "$h/Library/Application Support/Microsoft Edge" \
            "$h/Library/Application Support/BraveSoftware/Brave-Browser" \
            "$h/Library/Application Support/Chromium" \
            "$h/Library/Application Support/Vivaldi" \
            "$h/Library/Application Support/Comet" \
            "$h/Library/Application Support/Arc" \
            "$h/Library/Application Support/Dia" \
            "$h/Library/Application Support/company.thebrowser.dia"; do
            [[ -d "$broot" ]] || continue
            browser="$("$BASENAME" "$broot")"
            # Depth 6 catches Arc/Dia's extra "User Data" level.
            "$FIND" "$broot" -maxdepth 6 -path '*/Extensions/*/manifest.json' 2>/dev/null | "$HEAD" -n 500 | while IFS= read -r mf; do
                # Accept only Extensions/<id>/<version>/manifest.json.
                [[ "$("$BASENAME" "$("$DIRNAME" "$("$DIRNAME" "$("$DIRNAME" "$mf")")")")" == "Extensions" ]] || continue
                extid="$("$BASENAME" "$("$DIRNAME" "$("$DIRNAME" "$mf")")")"
                known="$(chrome_ext_known "$extid")"
                if [[ -n "$known" ]]; then
                    # Store ID is stable; location records the browser.
                    emit "BROWSER-EXT" "$known" "$extid" "$browser"
                    continue
                fi
                nm="$("$GREP" -Eo '"name"[[:space:]]*:[[:space:]]*"[^"]*"' "$mf" 2>/dev/null | "$HEAD" -1 | "$SED" -E 's/.*:[[:space:]]*"//; s/"$//')"
                case "$nm" in
                    __MSG_*)
                        extdir="$("$DIRNAME" "$("$DIRNAME" "$mf")")"
                        msg="$("$FIND" "$extdir" -maxdepth 3 -path '*_locales/en*/messages.json' 2>/dev/null | "$HEAD" -1)"
                        [[ -n "$msg" ]] && nm="$("$GREP" -Eo '"message"[[:space:]]*:[[:space:]]*"[^"]*"' "$msg" 2>/dev/null | "$HEAD" -1 | "$SED" -E 's/.*:[[:space:]]*"//; s/"$//')"
                        ;;
                esac
                [[ -z "$nm" ]] && continue
                if is_ai_heuristic "$nm"; then
                    emit "BROWSER-EXT" "$nm" "$browser" "$mf"
                fi
            done
        done
    done
}

# SECTION E: MCP configuration on stable user and system paths.
scan_mcp() {
    local h cdc vsc f
    local -a cdext plugmcp kirows
    for h in $user_homes; do
        # Claude Desktop config.
        cdc="$h/Library/Application Support/Claude/claude_desktop_config.json"
        [[ -f "$cdc" ]] && "$GREP" -q 'mcpServers' "$cdc" 2>/dev/null && emit "MCP" "Claude Desktop MCP" "configured" "$cdc"
        # Desktop Extensions can bundle MCP servers outside claude_desktop_config.json.
        cdext=("$h/Library/Application Support/Claude/Claude Extensions"/*(N/))
        (( ${#cdext} )) && emit "MCP" "Claude Desktop Extensions MCP" "${#cdext} extension bundle(s)" "$h/Library/Application Support/Claude/Claude Extensions"
        # Claude Code user scope.
        [[ -f "$h/.claude.json" ]] && "$GREP" -q 'mcpServers' "$h/.claude.json" 2>/dev/null && emit "MCP" "Claude Code MCP" "configured" "$h/.claude.json"
        # Claude Code plugin MCP manifests.
        plugmcp=("$h"/.claude/plugins/**/.mcp.json(N))
        (( ${#plugmcp} )) && emit "MCP" "Claude Code plugin MCP" "${#plugmcp} plugin manifest(s)" "$h/.claude/plugins"
        # Cursor user scope.
        [[ -f "$h/.cursor/mcp.json" ]] && emit "MCP" "Cursor MCP" "configured" "$h/.cursor/mcp.json"
        # OpenAI Codex CLI.
        [[ -f "$h/.codex/config.toml" ]] && "$GREP" -qi 'mcp' "$h/.codex/config.toml" 2>/dev/null && emit "MCP" "Codex MCP" "configured" "$h/.codex/config.toml"
        # VS Code family user-profile MCP config.
        for vsc in "$h/Library/Application Support/Code" \
                   "$h/Library/Application Support/Code - Insiders" \
                   "$h/Library/Application Support/VSCodium"; do
            for f in "$vsc/User/mcp.json" "$vsc/User/profiles"/*/mcp.json(N); do
                [[ -f "$f" ]] && "$GREP" -q '"servers"' "$f" 2>/dev/null && emit "MCP" "VS Code MCP" "configured" "$f"
            done
        done
        # Gemini CLI.
        [[ -f "$h/.gemini/settings.json" ]] && "$GREP" -q 'mcpServers' "$h/.gemini/settings.json" 2>/dev/null && emit "MCP" "Gemini CLI MCP" "configured" "$h/.gemini/settings.json"
        # Kiro user and workspace config.
        [[ -f "$h/.kiro/settings/mcp.json" ]] && emit "MCP" "Kiro MCP" "configured" "$h/.kiro/settings/mcp.json"
        # Windsurf.
        [[ -f "$h/.codeium/windsurf/mcp_config.json" ]] && emit "MCP" "Windsurf MCP" "configured" "$h/.codeium/windsurf/mcp_config.json"
        # Zed.
        [[ -f "$h/.config/zed/settings.json" ]] && "$GREP" -q 'context_servers' "$h/.config/zed/settings.json" 2>/dev/null && emit "MCP" "Zed MCP" "configured" "$h/.config/zed/settings.json"
        # LM Studio.
        [[ -f "$h/.lmstudio/mcp.json" ]] && "$GREP" -q 'mcpServers' "$h/.lmstudio/mcp.json" 2>/dev/null && emit "MCP" "LM Studio MCP" "configured" "$h/.lmstudio/mcp.json"
        # Goose.
        [[ -f "$h/.config/goose/config.yaml" ]] && "$GREP" -q 'extensions' "$h/.config/goose/config.yaml" 2>/dev/null && emit "MCP" "Goose MCP" "configured" "$h/.config/goose/config.yaml"
    done
    # Claude Code fleet-managed MCP path.
    [[ -f "/Library/Application Support/ClaudeCode/managed-mcp.json" ]] && emit "MCP" "Claude Code managed MCP (fleet policy)" "configured" "/Library/Application Support/ClaudeCode/managed-mcp.json"
}

# Each scan section is isolated so one failure does not hide the rest.
if (( WORK_OK )); then
    scan_apps        2>/dev/null
    scan_cli         2>/dev/null
    scan_ide_ext     2>/dev/null
    scan_browser_ext 2>/dev/null
    scan_mcp         2>/dev/null
fi

# Assemble the cached EA inner value.
if (( ! WORK_OK )); then
    # Preserve the previous state on scanner infrastructure failure.
    print -u2 "ai-inventory-collector: scratch file unavailable; leaving previous state file untouched"
    exit 1
fi
if [[ ! -s "$WORK" ]]; then
    body="None"
else
    sorted="$("$SORT" -u "$WORK")"

    # Collapse multiple evidence paths into one row per category/tool.
    sorted="$(printf '%s\n' "$sorted" | "$AWK" -F'\t' '
        BEGIN {
            OFS = "\t"
            alias["anthropic ai claude code"] = "claude code"
            alias["google gemini cli"]        = "gemini cli"
            alias["github copilot"]           = "github copilot cli"
            alias["opencode ai"]              = "opencode"
            alias["sourcegraph amp"]          = "amp"
            alias["continuedev cli"]          = "continue cli"
            alias["augmentcode auggie"]       = "auggie"
            alias["auggie augment"]           = "auggie"
            alias["antinomyhq forge"]         = "forgecode"
            alias["vibe kit grok cli"]        = "grok cli"
            alias["qwen code qwen code"]      = "qwen code"
            alias["shareai lab kode"]         = "kode"
            alias["amazon q developer cli"]   = "amazon q"
            alias["llm"]                      = "llm cli"
            alias["aider chat"]               = "aider"
        }
        {
            key = tolower($2)
            sub(/^(npm|pipx|uv): /, "", key)
            gsub(/ *\([^)]*\)/, "", key)
            gsub(/[-_\/@]/, " ", key)
            gsub(/  +/, " ", key); sub(/^ +/, "", key); sub(/ +$/, "", key)
            if (key in alias) key = alias[key]
            k = $1 SUBSEP key
            if (!(k in row)) { row[k] = ++n; cat[n] = $1; fr[n] = $2; id[n] = $3; loc[n] = $4 }
            else { i = row[k]; loc[i] = loc[i] "; " $4 }
        }
        END { for (i = 1; i <= n; i++) print cat[i], fr[i], id[i], loc[i] }
    ')"

    count="$(printf '%s\n' "$sorted" | "$GREP" -c .)"

    # ${(f)...} splits command output on newlines in zsh.
    cats=""
    for c in ${(f)"$(printf '%s\n' "$sorted" | "$CUT" -f1 | "$SORT" -u)"}; do
        case "$c" in
            APP)         kw="ai-app";;
            CLI)         kw="ai-cli";;
            IDE-EXT)     kw="ide-ai-extension";;
            BROWSER-EXT) kw="browser-ai-extension";;
            MCP)         kw="mcp-config";;
            HEURISTIC)   kw="ai-unknown-review";;
            *)           kw="$(lc "$c")";;
        esac
        cats="$cats, $kw"
    done
    cats="${cats#, }"

    findings_body="$(printf '%s\n' "$sorted" | "$SED" 's/\t/ | /g')"
    body="$(printf 'SUMMARY: %s finding(s); categories: %s\n%s' "$count" "$cats" "$findings_body")"
fi

# Write atomically so recon sees either the old complete file or the new one.
"$MKDIR" -p "$STATE_DIR" 2>/dev/null
if (( UID == 0 )); then
    "$CHOWN" root:wheel "$STATE_DIR" 2>/dev/null
fi
"$CHMOD" 0700 "$STATE_DIR" 2>/dev/null   # root-only: the only reader (the EA) is root

tmpfile="$STATE_FILE.tmp.$$"
if ! printf '%s' "$body" > "$tmpfile"; then
    print -u2 "ai-inventory-collector: failed to write temporary state file: $tmpfile"
    exit 1
fi
if (( UID == 0 )); then
    "$CHOWN" root:wheel "$tmpfile" 2>/dev/null
fi
"$CHMOD" 0600 "$tmpfile" 2>/dev/null   # root-only: usernames/paths are mildly sensitive
if ! "$MV" -f "$tmpfile" "$STATE_FILE"; then
    print -u2 "ai-inventory-collector: failed to rename temporary state file into place: $STATE_FILE"
    exit 1
fi

exit 0
__AI_COLLECTOR_EOF__
chown root:wheel "${COLLECTOR_DEST}"
chmod 0755 "${COLLECTOR_DEST}"

log "Creating state directory ${STATE_DIR}"
mkdir -p "${STATE_DIR}"
chown root:wheel "${STATE_DIR}"
chmod 0700 "${STATE_DIR}"

log "Recording interval ${START_INTERVAL}s -> ${STATE_DIR}/interval (EA staleness = 2x)"
printf '%s\n' "${START_INTERVAL}" > "${STATE_DIR}/interval"
chown root:wheel "${STATE_DIR}/interval"
chmod 0644 "${STATE_DIR}/interval"

log "Writing LaunchDaemon ${PLIST_DEST} (Label ${LABEL})"
cat > "${PLIST_DEST}" <<PLIST_EOF
<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE plist PUBLIC "-//Apple//DTD PLIST 1.0//EN" "http://www.apple.com/DTDs/PropertyList-1.0.dtd">
<plist version="1.0">
<dict>
	<key>Label</key>
	<string>${LABEL}</string>
	<key>ProgramArguments</key>
	<array>
		<string>/bin/zsh</string>
		<string>--no-rcs</string>
		<string>${COLLECTOR_DEST}</string>
	</array>
	<key>StartInterval</key>
	<integer>${START_INTERVAL}</integer>
	<key>RunAtLoad</key>
	<true/>
	<key>ProcessType</key>
	<string>Background</string>
	<key>StandardOutPath</key>
	<string>${LOG_FILE}</string>
	<key>StandardErrorPath</key>
	<string>${LOG_FILE}</string>
</dict>
</plist>
PLIST_EOF
chown root:wheel "${PLIST_DEST}"
chmod 0644 "${PLIST_DEST}"

log "(Re)loading via modern launchctl subcommands (bootout/enable/bootstrap/kickstart)"
launchctl bootout "system/${LABEL}" 2>/dev/null || true
# Clear a persistent disabled override before bootstrap.
launchctl enable "system/${LABEL}"
launchctl bootstrap system "${PLIST_DEST}"
launchctl kickstart -k "system/${LABEL}"

log "Done. Verify with: launchctl print system/${LABEL}"
log "First state file should appear within a few seconds at ${STATE_DIR}/result.txt"
exit 0
